C语言中的队列实现及其入队与出队方法
在计算机科学中，队列是一种重要的数据结构，具有先进先出（FIFO, First-In-First-Out）的特点。队列广泛应用于各种场景，如任务调度、数据缓冲、打印任务管理等。在C语言中，我们可以通过数组或链表来实现队列。本文将详细介绍如何在C语言中实现队列，并重点阐述其入队和出队的方法。
一、队列的基本概念
队列是一种线性数据结构，其特点是：

先进先出：最先插入的元素最先被删除。
操作：
入队（enqueue）：将元素添加到队列的尾部。
出队（dequeue）：从队列的头部移除元素。

二、队列的实现
1. 基于数组的队列实现
使用数组来实现队列是一种简单的方式，但要注意队列的大小固定。以下是基于数组的队列实现示例：
#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SIZE 100 // 定义队列的最大容量

typedef struct {
    int items[MAX_SIZE];
    int front;
    int rear;
} Queue;

// 初始化队列
void initializeQueue(Queue* q) {
    q->front = -1;
    q->rear = -1;
}

// 判断队列是否为空
bool isEmpty(Queue* q) {
    return q->front == -1;
}

// 判断队列是否为满
bool isFull(Queue* q) {
    return (q->rear + 1) % MAX_SIZE == q->front;
}

// 入队
void enqueue(Queue* q, int value) {
    if (isFull(q)) {
        printf("队列已满，无法入队。\n");
        return;
    }
    if (isEmpty(q)) {
        q->front = 0;
    }
    q->rear = (q->rear + 1) % MAX_SIZE;
    q->items[q->rear] = value;
    printf("入队: %d\n", value);
}

// 出队
int dequeue(Queue* q) {
    if (isEmpty(q)) {
        printf("队列为空，无法出队。\n");
        return -1; // 返回一个无效值表示队列为空
    }
    int item = q->items[q->front];
    if (q->front == q->rear) { // 如果队列只有一个元素
        q->front = -1;
        q->rear = -1;
    } else {
        q->front = (q->front + 1) % MAX_SIZE;
    }
    printf("出队: %d\n", item);
    return item;
}

// 打印队列
void displayQueue(Queue* q) {
    if (isEmpty(q)) {
        printf("队列为空。\n");
        return;
    }
    int i = q->front;
    printf("队列元素: ");
    while (i != q->rear) {
        printf("%d ", q->items[i]);
        i = (i + 1) % MAX_SIZE;
    }
    printf("%d\n", q->items[i]);
}

int main() {
    Queue q;
    initializeQueue(&q);

    enqueue(&q, 10);
    enqueue(&q, 20);
    enqueue(&q, 30);

    displayQueue(&q);

    dequeue(&q);
    displayQueue(&q);

    enqueue(&q, 40);
    displayQueue(&q);

    return 0;
}

